SELECT qn.quantitative_evaluation_id AS quantitativeEvaluationId, qn.employee_id AS employeeId, e.employee_name AS employeeName, qn.eval_period_id AS evalPeriodId, ep.eval_year AS evalYear, ep.eval_sequence AS evalSequence, qn.t_score AS tScore, qn.status FROM quantitative_evaluation qn JOIN employee e ON e.employee_id = qn.employee_id JOIN evaluation_period ep ON ep.eval_period_id = qn.eval_period_id
AND qn.eval_period_id = #{periodId}
AND qn.status = #{status}
ORDER BY ep.eval_year DESC, ep.eval_sequence DESC, e.employee_name ASC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM quantitative_evaluation qn


        AND qn.eval_period_id = #{periodId}


        AND qn.status = #{status}
